#!/bin/bash
set -e
echo "=== Starting VoiceFlow Bridge Deploy ==="
python3 -c "import base64; open('/opt/voiceflow/sip-bridge/sip-manager.js','wb').write(base64.b64decode(''))" && echo "OK: sip-manager.js"
python3 -c "import base64; open('/opt/voiceflow/sip-bridge/call-manager.js','wb').write(base64.b64decode(''))" && echo "OK: call-manager.js"
python3 -c "import base64; open('/opt/voiceflow/sip-bridge/index.js','wb').write(base64.b64decode(''))" && echo "OK: index.js"
python3 -c "import base64; open('/opt/voiceflow/sip-bridge/dashboard.js','wb').write(base64.b64decode(''))" && echo "OK: dashboard.js"
pm2 restart voiceflow-bridge && echo "=== DEPLOY COMPLETE ==="